/**
 * @summary Start an export job
 */
export const getCreateExportUrl = (projectId: number) => {
  return `/api/projects/${projectId}/exports`;
};

export const createExport = async (
  projectId: number,
  exportInput: ExportInput,
  options?: RequestInit,
): Promise<Export> => {
  return customFetch<Export>(getCreateExportUrl(projectId), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(exportInput),
  });
};

export const getCreateExportMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof createExport>>,
    TError,
    { projectId: number; data: BodyType<ExportInput> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof createExport>>,
  TError,
  { projectId: number; data: BodyType<ExportInput> },
  TContext
> => {
  const mutationKey = ["createExport"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof createExport>>,
    { projectId: number; data: BodyType<ExportInput> }
  > = (props) => {
    const { projectId, data } = props ?? {};

    return createExport(projectId, data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type CreateExportMutationResult = NonNullable<
  Awaited<ReturnType<typeof createExport>>
>;
export type CreateExportMutationBody = BodyType<ExportInput>;
export type CreateExportMutationError = ErrorType<unknown>;

