/**
 * @summary Get export job status
 */
export const getGetExportUrl = (projectId: number, exportId: number) => {
  return `/api/projects/${projectId}/exports/${exportId}`;
};

export const getExport = async (
  projectId: number,
  exportId: number,
  options?: RequestInit,
): Promise<Export> => {
  return customFetch<Export>(getGetExportUrl(projectId, exportId), {
    ...options,
    method: "GET",
  });
};

export const getGetExportQueryKey = (projectId: number, exportId: number) => {
  return [`/api/projects/${projectId}/exports/${exportId}`] as const;
};

export const getGetExportQueryOptions = <
  TData = Awaited<ReturnType<typeof getExport>>,
  TError = ErrorType<unknown>,
>(
  projectId: number,
  exportId: number,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getExport>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetExportQueryKey(projectId, exportId);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getExport>>> = ({
    signal,
  }) => getExport(projectId, exportId, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!(projectId && exportId),
    ...queryOptions,
  } as UseQueryOptions<Awaited<ReturnType<typeof getExport>>, TError, TData> & {
    queryKey: QueryKey;
  };
};

export type GetExportQueryResult = NonNullable<
  Awaited<ReturnType<typeof getExport>>
>;
export type GetExportQueryError = ErrorType<unknown>;

/**
 * @summary Get export job status
 */

export function useGetExport<
  TData = Awaited<ReturnType<typeof getExport>>,
  TError = ErrorType<unknown>,
>(
  projectId: number,
  exportId: number,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getExport>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetExportQueryOptions(projectId, exportId, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

